// Basic async/await
async function getUser(id) {
  const response = await fetch(`/api/users/${id}`);
  const user = await response.json();
  return user;
}

// Error handling
async function safeGetUser(id) {
  try {
    const user = await getUser(id);
    console.log(user);
  } catch (error) {
    console.error('Failed:', error.message);
  } finally {
    console.log('Request complete');
  }
}

// ❌ Sequential (slow — waits one by one)
async function slow() {
  const u1 = await getUser(1); // wait...
  const u2 = await getUser(2); // then wait...
}

// ✅ Parallel (fast — both requests fire at once)
async function fast() {
  const [u1, u2] = await Promise.all([getUser(1), getUser(2)]);
}
